import os
import httpx
from fastapi import FastAPI, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from dotenv import load_dotenv

load_dotenv()

app = FastAPI()

# CORS configuration for React frontend
app.add_middleware(
    CORSMiddleware,
    allow_origins=["http://localhost:3000"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

# Environment variables
FLW_PUBLIC_KEY = os.getenv("FLUTTERWAVE_PUBLIC_KEY")
FLW_SECRET_KEY = os.getenv("FLUTTERWAVE_SECRET_KEY")
FLW_BASE_URL = "https://api.flutterwave.com/v3"

# Request/Response models
class PaymentInitRequest(BaseModel):
    amount: float
    customer_email: str
    customer_name: str
    customer_phone: str
    description: str

class PaymentVerifyRequest(BaseModel):
    transaction_id: str

class PaymentResponse(BaseModel):
    status: str
    message: str
    data: dict = None

# Health check endpoint
@app.get("/health")
def health_check():
    return {"status": "ok"}

# Initialize payment transaction [4]
@app.post("/api/payments/initialize", response_model=PaymentResponse)
async def initialize_payment(payload: PaymentInitRequest):
    """
    Initialize a Flutterwave payment.
    Returns tx_ref for frontend to use with checkout modal.
    """
    try:
        # Generate unique transaction reference
        import time
        tx_ref = f"flw_{int(time.time() * 1000)}"

        # Prepare payment data
        payment_data = {
            "tx_ref": tx_ref,
            "amount": payload.amount,
            "currency": "NGN",
            "payment_options": "card,mobilemoney,ussd",
            "customer": {
                "email": payload.customer_email,
                "name": payload.customer_name,
                "phonenumber": payload.customer_phone,
            },
            "customizations": {
                "title": "Payment",
                "description": payload.description,
                "logo": "https://flutterwave.com/images/logo-colored.svg",
            },
        }

        return PaymentResponse(
            status="success",
            message="Payment initialized",
            data={
                "tx_ref": tx_ref,
                "public_key": FLW_PUBLIC_KEY,
                "amount": payload.amount,
                "currency": "NGN",
                "payment_options": "card,mobilemoney,ussd",
                "customer": payment_data["customer"],
                "customizations": payment_data["customizations"],
            }
        )
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))

# Verify transaction after payment [4]
@app.post("/api/payments/verify", response_model=PaymentResponse)
async def verify_payment(payload: PaymentVerifyRequest):
    """
    Verify a Flutterwave transaction using the transaction ID.
    Called server-side after payment redirect.
    """
    try:
        headers = {
            "Authorization": f"Bearer {FLW_SECRET_KEY}",
            "Content-Type": "application/json"
        }

        # Query Flutterwave API to verify transaction
        async with httpx.AsyncClient() as client:
            response = await client.get(
                f"{FLW_BASE_URL}/transactions/{payload.transaction_id}/verify",
                headers=headers
            )

        if response.status_code != 200:
            raise HTTPException(
                status_code=400,
                detail="Transaction verification failed"
            )

        result = response.json()
        transaction_data = result.get("data", {})

        # Verify transaction status
        if transaction_data.get("status") == "successful":
            return PaymentResponse(
                status="success",
                message="Payment verified successfully",
                data={
                    "transaction_id": transaction_data.get("id"),
                    "tx_ref": transaction_data.get("tx_ref"),
                    "amount": transaction_data.get("amount"),
                    "currency": transaction_data.get("currency"),
                    "customer": {
                        "email": transaction_data.get("customer", {}).get("email"),
                        "name": transaction_data.get("customer", {}).get("name"),
                    },
                    "payment_type": transaction_data.get("payment_type"),
                    "processor_response": transaction_data.get("processor_response"),
                }
            )
        else:
