        }}
      >
        {loading ? 'Processing...' : 'Pay with Flutterwave'}
      </button>

      {/* Status Message */}
      {paymentStatus && (
        <div
          style={{
            marginTop: '20px',
            padding: '15px',
            borderRadius: '4px',
            backgroundColor: paymentStatus.success ? '#d4edda' : '#f8d7da',
