          }}
        >
          <p>{paymentStatus.message}</p>
          {paymentStatus.data && (
            <details>
              <summary>Transaction Details</summary>
              <pre style={{ fontSize: '12px', overflow: 'auto' }}>
                {JSON.stringify(paymentStatus.data, null, 2)}
              </pre>
            </details>
          )}
        </div>
      )}
    </div>
  );
}
