### 3. Complete Code Examples

#### Backend: FastAPI (`main.py`)
This endpoint accepts the `tx_ref` from the frontend redirect and validates it against Flutterwave using `rave-python`.

```python
import os
from fastapi import FastAPI, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from rave_python import Rave, RaveExceptions
from dotenv import load_dotenv

load_dotenv()

app = FastAPI()

# Enable CORS for React frontend
app.add_middleware(
    CORSMiddleware,
    allow_origins=["http://localhost:3000"],
    allow_methods=["*"],
    allow_headers=["*"],
)

# Initialize rave-python
rave = Rave(
    os.getenv("FLW_PUBLIC_KEY"), 
    os.getenv("FLW_SECRET_KEY"), 
    production=False,  # Set to True in prod
    usingEnv=False
)

class VerifyRequest(BaseModel):
    tx_ref: str

@app.post("/verify-payment")
async def verify_payment(req: VerifyRequest):
    try:
        # rave-python natively handles the v2 verify endpoint
        # .Card.verify applies to mobile money tx_refs perfectly
        res = rave.Card.verify(req.tx_ref)

        # Security: Always check transaction status, amount, and currency!
        # Assume `db_amount` is fetched from your database using req.tx_ref
        db_amount = 10000 

        if res.get("currency") == "NGN" and res.get("amount") >= db_amount:
            # Mark order as Paid in DB
            return {"status": "success", "message": "Payment verified securely."}
        else:
            raise HTTPException(status_code=400, detail="Value or currency mismatch.")

    except RaveExceptions.TransactionVerificationError as e:
        raise HTTPException(status_code=400, detail=str(e.err["errMsg"]))
    except Exception as e:
        raise HTTPException(status_code=500, detail="Internal server error")
```

